import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"70. Parental Leave","description":"","frontmatter":{"title":"70. Parental Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","parental-leave","employment","preliminary"]},"headers":[],"relativePath":"ebas/mspp/leave/70-parental-leave.md","filePath":"ebas/mspp/leave/70-parental-leave.md"}'),n={name:"ebas/mspp/leave/70-parental-leave.md"};function i(s,e,p,l,h,d){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_70-parental-leave" tabindex="-1">70. Parental Leave <a class="header-anchor" href="#_70-parental-leave" aria-label="Permalink to &quot;70. Parental Leave&quot;">​</a></h1><p>The NES contains applicable terms regarding parental leave including terms regarding Stillborn children and Hospitalised children.</p><p><strong>70.1</strong> Application of this clause</p><p><strong>a.</strong> Subject to the terms of this clause Employees are entitled to paid and unpaid parental leave and to work part-time in connection with the birth or adoption of a child.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>b.</strong> The provisions of this clause apply to full-time, part-time and eligible Casual Employees but do not apply to other casual Employees.</p><p><strong>c.</strong> An Employer must not fail to re-engage a Casual Employee because:</p><p><strong>(i)</strong> the Employee or Employee’s spouse is pregnant; or</p><p><strong>(ii)</strong> the Employee is or has been absent on Parental Leave.</p><p><strong>d.</strong> The rights of an Employer in relation to engagement and re-engagement of Casual Employees are not affected, other than in accordance with this clause.</p><p><strong>70.2</strong> Definitions</p><p><strong>a.</strong> Eligible Casual Employee means a Casual Employee employed pursuant to <a href="/eba/ebas/mspp/employment/25-casual-employment.html">clause 25</a> and who is:</p><p><strong>(i)</strong> employed by an Employer on a regular and systematic basis for a sequence of periods of employment during a period of at least 12 months; and</p><p><strong>(ii)</strong> who has, but for the pregnancy or the decision to adopt, a reasonable expectation of ongoing employment on a regular and systematic basis.</p><p><strong>b.</strong> Child means:</p><p><strong>(i)</strong> a child (or children from a multiple birth) of the Employee or the Employee&#39;s Spouse; or,</p><p><strong>(ii)</strong> in relation to adoption-related leave, a child under 16 (as at the day of placement or expected day of placement) who is placed or to be placed with the Employee for the purposes of adoption, other than a child or step-child of the Employee or their Spouse or a child who has previously lived continuously with the Employee for a period of six months or more (Adopted Child).</p><p><strong>(iii)</strong> as the case requires, includes a Stillborn Child.</p><p><strong>c.</strong> Flexible Parental Leave means 30 days&#39; unpaid parental which an Employee may take under subclause 70.8 as part of their 52 weeks&#39; entitlement of Parental Leave.</p><p><strong>d.</strong> For the purposes of this clause, Service (which includes Recognised Prior Service), is as defined in clause 9aa of this Agreement.</p><p><strong>e.</strong> For the purposes of this clause, spouse includes a person to whom the Employee is married and de facto partner, former spouse or former de facto partner. The Employee’s “de facto partner” means a person who lives with the Employee as husband, wife or same sex partner on a bona fide domestic basis, although not legally married to the Employee.</p><p><strong>70.3</strong> Basic Entitlement</p><p><strong>a.</strong> An Employee with six months Service under this Agreement, is entitled to 52 weeks of paid and unpaid Parental Leave as outlined at 70.3c below, if the leave is associated with the birth or adoption of their child.</p><p><strong>b.</strong> An Employee who does not satisfy the qualifying service requirement for the paid components of leave shall be entitled to leave without pay for a period not exceeding 52 weeks.</p><p><strong>c.</strong> From 21 December 2021, leave available is summarised in the following table:</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>Type of leave Paid leave Total combined paid and unpaid leave Primary carer leave 14 weeks 52 weeks Secondary carer Leave 2 week 52 weeks Adoption leave – primary carer leave 14 weeks 52 weeks Adoption leave – secondary carer 2 week 3 Weeks leave Flexible Parental Leave N/A 30 days unpaid leave</p><p>Provided that for paid leave for the Primary carer is taken contemporaneously with the birth or placement of the Child</p><p><strong>d.</strong> For the purposes of this clause pay shall be defined in the same terms as for Long Service Leave as prescribed by <a href="/eba/ebas/mspp/leave/67-long-service-leave.html">clause 67.2</a> of this Agreement.</p><p><strong>e.</strong> The Employer and Employee may reach agreement as to how the paid parental leave under this Agreement is paid. For example, the entitlement may be paid at the commencement of leave, paid in smaller amounts over a longer period, consecutively or concurrently with any relevant Commonwealth Government parental leave scheme (subject to the requirements of any applicable legislation) and may include a voluntary contribution to superannuation.</p><p><strong>f.</strong> Such agreement at (e) must be in writing and signed by the parties. The Employee must nominate a preferred payment arrangement at least four weeks prior to the expected date of birth or date of placement of the child. In the absence of agreement, leave will be paid during the ordinary pay periods corresponding with the period of the leave.</p><p><strong>g.</strong> Employees who already receive Parental Leave (however titled) payments in excess of those above shall not suffer any disadvantage.</p><p><strong>h.</strong> Subject to 70.8 hereof, Parental Leave is to be available to only one parent at a time, in a single unbroken period, except that both parents may simultaneously take up to 8 weeks leave (in which case the leave does not need to be taken in a single unbroken period).</p><p><strong>i.</strong> in the case of two week’s paid secondary carer leave an Employee shall be entitled to a total of 10 days (which need not be taken consecutively) in connection with the birth of a child for whom they have accepted responsibility which may be commenced 1 week prior to the expected date of birth, and in the case of short adoption leave for the secondary care giver, two week’s paid leave and up to 6 weeks’ unpaid leave (8 weeks in total) which may be commenced at the time of placement.</p><p><strong>70.4</strong> Primary Carer Leave</p><p><strong>a.</strong> An Employee must provide notice to the Employer in advance of the expected date of commencement of Parental Leave. The notice requirements are:</p><p><strong>(i)</strong> of the expected date of the birth (included in a certificate from a registered medical practitioner stating that the Employee is pregnant) - at least ten weeks; or</p><p><strong>(ii)</strong> of the date on which the Employee proposes to commence primary carer leave and the period of leave to be taken - at least four weeks.</p><p><strong>b.</strong> When the Employee gives notice under 70.4 hereof the Employee must also provide a statutory declaration stating particulars of any period of secondary</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>carer leave sought or taken by their spouse and that for the period of primary carer leave, they will not engage in any conduct inconsistent with their contract of employment.</p><p><strong>c.</strong> An Employee will not be in breach of this clause if failure to give the stipulated notice is occasioned by the birth occurring earlier than the presumed date.</p><p><strong>d.</strong> An Employee shall be entitled to work until their estimated date of birth except where this would present a risk to the Employee or the unborn child.</p><p><strong>e.</strong> Subject to 70.4a hereof and unless agreed otherwise between the Employer and Employee, an Employee may commence Parental Leave at any time within six weeks immediately prior to the expected date of birth.</p><p><strong>f.</strong> Where an Employee continues to work within the six week period immediately prior to the expected date of birth of the child or is on paid leave under 70.14b an Employer may require the Employee to provide a medical certificate stating that they are fit to work on normal duties.</p><p><strong>g.</strong> If a statement is not provided then the Employer will make all practical efforts to remedy the unsafe situation and if this is not possible, the Employee will be offered a safe, alternate position in accordance with sub-clause 70.14 herein.</p><p><strong>70.5</strong> Special Maternity Leave and Personal Leave</p><p><strong>a.</strong> Where the pregnancy of an Employee not then on Parental Leave ends other than by the birth of a living child, the Employee may take leave for such periods (certified period) as a registered medical practitioner certifies as necessary (special maternity leave), as follows:</p><p><strong>(i)</strong> Where the pregnancy ends within 20 weeks of the expected date of birth of the child otherwise than by the birth of a living child, the Employee is entitled to access any paid and/or unpaid personal leave entitlements in accordance with the relevant personal leave provisions; or</p><p><strong>(ii)</strong> Where the pregnancy terminates after the completion of 20 weeks, the Employee is entitled during the certified period/s to paid special maternity leave not exceeding the amount of paid primary carer leave available under 70.3 and thereafter, to unpaid special maternity leave.</p><p><strong>b.</strong> The Employee is entitled to a period of unpaid special maternity leave if they are not fit for work during that period because they have a pregnancy related illness.</p><p><strong>c.</strong> An Employee must give notice of taking unpaid special maternity leave as soon as practicable (which may be a time after the leave has started) and advise their Employer of the period or expected period of the leave.</p><p><strong>d.</strong> An Employee who has given their Employer notice under 70.5c must, if required by the Employer, give the Employer evidence that would satisfy a reasonable person that the leave is taken for a reason specified in clause 70.5a. An Employer may require the evidence to be a medical certificate.</p><p><strong>e.</strong> Where special maternity leave is granted under this subclause, during the period of leave an Employee may return to work at any time, as agreed between the Employer and the Employee provided that time does not exceed four weeks from the recommencement date desired by the Employee.</p><p><strong>f.</strong> Nothing in this subclause is intended to derogate from the entitlement to unpaid special maternity leave in the NES.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>70.6</strong> Secondary Carer Leave</p><p><strong>a.</strong> An Employee will provide to the Employer at least ten weeks prior to each proposed period of secondary carer leave, with:</p><p><strong>(i)</strong> a certificate from a registered medical practitioner which names their spouse, states that they are pregnant and the expected date of birth, or states the date on which the birth took place; and</p><p><strong>(ii)</strong> written notification of the dates on which they propose to start and finish the period of secondary carer leave; and</p><p><strong>(iii)</strong> a statutory declaration stating: <strong>(A)</strong> except in relation to leave taken simultaneously with the child’s primary carer under clause 70.3h or clause 70.8, that they will take the period of Parental Leave to become the primary care-giver of a child; <strong>(B)</strong> particulars of any period of Primary Carer Leave sought or taken by their spouse; and <strong>(C)</strong> that for the period of Secondary Carer Leave they will not engage in any conduct inconsistent with their contract of employment.</p><p><strong>b.</strong> The Employee will not be in breach of this clause 70.6 if the failure to give the required period of notice is because of the birth occurring earlier than expected, the death of the mother of the child, or other compelling circumstances.</p><p><strong>70.7</strong> Adoption Leave</p><p><strong>a.</strong> The Employee shall be required to provide the Employer with written notice of their intention to apply for adoption leave as soon as is reasonably practicable after receiving a placement approval notice from an adoption agency or other appropriate body.</p><p><strong>b.</strong> The Employee must give written notice of the day when the placement with the Employee is expected to start as soon as possible after receiving a placement notice indicating the expected placement day.</p><p><strong>c.</strong> The Employee must give the following written notice of the first and last days of any period of adoption leave they intend to apply for because of the placement:</p><p><strong>(i)</strong> Where a placement notice is received within the period of 8 weeks after receiving the placement approval notice – before the end of that 8 week period; or</p><p><strong>(ii)</strong> Where a placement notice is received after the end of the period of 8 weeks after receiving the placement approval notice – as soon as reasonably practicable after receiving the placement notice.</p><p><strong>d.</strong> As a general rule, the Employee must make application for leave to the Employer at least ten weeks in advance of the date of commencement of long adoption leave and the period of leave to be taken, or 14 days in advance for short adoption leave. An Employee may commence adoption leave prior to providing such notice, where through circumstances beyond the control of the Employee, the adoption of a child takes place earlier.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>e.</strong> Before commencing adoption leave, an Employee will provide the Employer with a statement from an adoption agency of the day when the placement is expected to start and a statutory declaration stating:</p><p><strong>(i)</strong> that the child is an eligible child, whether the Employee is taking short or long adoption leave or both and the particulars of any other authorised leave to be taken because of the placement;</p><p><strong>(ii)</strong> except in relation to leave taken simultaneously with the child’s other adoptive parent under clause 70.3h or clause 70.8 that the Employee is seeking adoption leave to become the primary care-giver of the child;</p><p><strong>(iii)</strong> particulars of any period of adoption leave sought or taken by the Employee’s spouse; and</p><p><strong>(iv)</strong> that for the period of adoption leave the Employee will not engage in any conduct inconsistent with their contract of employment.</p><p><strong>f.</strong> An Employee must provide the Employer with confirmation from the adoption agency of the start of the placement.</p><p><strong>g.</strong> Where the placement of child for adoption with an Employee does not proceed or continue, the Employee will notify the Employer immediately and the Employer will nominate a time not exceeding four weeks from receipt of notification for the Employee’s return to work.</p><p><strong>h.</strong> An Employee will not be in breach of this clause as a consequence of failure to give the stipulated periods of notice if such failure results from a requirement of an adoption agency to accept earlier or later placement of a child, the death of a spouse, or other compelling circumstances.</p><p><strong>i.</strong> An Employee seeking to adopt a child is entitled to unpaid leave for the purpose of attending any compulsory interviews or examinations as are necessary as part of the adoption procedure. The Employee and the Employer should agree on the length of the unpaid leave. Where agreement cannot be reached, the Employee is entitled to take up to two days unpaid leave. Where paid leave is available to the Employee, the Employer may require the Employee to take such leave instead.</p><p><strong>70.8</strong> Flexible Parental Leave</p><p><strong>a.</strong> An Employee may take up to 30 days of Parental Leave entitlement (Flexible Parental Leave) during the 24-month period starting on the date of birth (including a Stillbirth) or day of placement of the Child if the requirements of this sub-clause are satisfied in relation to the leave.</p><p><strong>b.</strong> The number of days of Flexible Parental Leave that the Employee takes must not be more than the number of flexible days notified to the Employer under sub-clause 70.9 (subject to any agreement under sub-clause 70.9d).</p><p><strong>(i)</strong> An Employee must take the Flexible Parental Leave as:</p><p><strong>(ii)</strong> a single continuous period of one or more days; or</p><p><strong>(iii)</strong> separate periods of one or more days each.</p><p><strong>c.</strong> An Employee may take the Flexible Long Parental Leave whether or not they have taken unpaid Parental Leave under subclause 70.4.</p><p><strong>d.</strong> An Employee may take Flexible Parental Leave after taking one or more periods of unpaid Primary Carer’s Leave only if the total of those periods (disregarding any extension under sub-clause 70.10 or 70.11) is no longer</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>than 12 months, less the Employee&#39;s Notional Flexible Period, provided that the calculation is based on the assumption that:</p><p><strong>(i)</strong> the Employee ordinarily works each day that is not a Saturday or Sunday; and</p><p><strong>(ii)</strong> there are no public holidays during the period.</p><p><strong>e.</strong> A member of an Employee Couple (the first Employee) may take Flexible Parental Leave on the same day as the other member of the Employee Couple (the other Employee) is taking unpaid Parental Leave only if the total of all periods of unpaid parental leave the first Employee takes at the same time as the other Employee is no longer than 8 weeks.</p><p><strong>70.9</strong> Notice requirements – Flexible Parental Leave</p><p><strong>a.</strong> If an Employee wishes to take Flexible Parental Leave, the Employee must give notice to the Employer as follows:</p><p><strong>(i)</strong> at the same time as the Employee provides notice for the original parental leave; or</p><p><strong>(ii)</strong> at least 10 weeks before starting the Flexible Parental Leave.</p><p><strong>b.</strong> The Employer may agree to a shorter period of notice.</p><p><strong>c.</strong> The notice provided must specify the total number of days (Flexible Days) of Flexible Parental Leave that the Employee intends to take.</p><p><strong>d.</strong> If the Employer agrees, the Employee may:</p><p><strong>(i)</strong> reduce the number of flexible days, including by reducing the number of flexible days to zero; or</p><p><strong>(ii)</strong> increase the number of flexible days up to 30.</p><p><strong>e.</strong> The Employee must give the Employer written notice of a flexible day on which the Employee will take Flexible Parental Leave:</p><p><strong>(i)</strong> at least 4 weeks before that day; or</p><p><strong>(ii)</strong> if that is not practicable, as soon as practicable (which may be a time after the leave has started).</p><p><strong>f.</strong> If the Employer agrees, the Employee may change a day on which the Employee takes Flexible Parental Leave from a day specified in a notice under subsection 70.9a.</p><p><strong>70.10</strong> Variation Of Period Of Parental Leave Up to 12 months</p><p><strong>a.</strong> Unless agreed otherwise between the Employer and Employee, where an Employee takes leave under clause 70.4 for less than the available period, the Employee may notify to their Employer to extend the period of parental leave within the available period on one occasion. Any such change must be notified in writing at least four weeks prior to the commencement of the changed arrangements. The notice must specify the new intended end date of the parental leave. Any further period of leave must be by agreement.</p><p><strong>b.</strong> If the Employer agrees, an Employee whose period of unpaid parental leave has started may reduce the period of unpaid Parental Leave they take (including any extension agreed under 70.11).</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>70.11</strong> Right to request an extension of period of unpaid parental leave beyond 12 months To assist in reconciling work and parental responsibilities, an Employee entitled to Parental Leave may request the Employer to extend the period of leave by a further continuous period of up to 12 months immediately following the end of the available parental leave.</p><p><strong>a.</strong> Request to be in writing The request must be in writing and must be given to the Employer at least four weeks before the end of the available parental leave period.</p><p><strong>b.</strong> Response to be in writing The Employer must give the Employee a written response stating whether the Employer grants or refuses the request. The response must be given as soon as practicable, and no later than 21 days after the request is made.</p><p><strong>c.</strong> Refusal only on reasonable business grounds The Employer may only refuse the request on reasonable business grounds.</p><p><strong>d.</strong> Reasons for refusal to be specified If the Employer refuses the request, the written response must include details of the reasons for the refusal.</p><p><strong>e.</strong> Reasonable opportunity to discuss The Employer must not refuse the request unless the Employer has given the Employee a reasonable opportunity to discuss the request.</p><p><strong>70.12</strong> Returning to work This clause does not limit any entitlement to make a request for flexible working arrangements under <a href="/eba/ebas/mspp/employment/27-flexible-working-arrangements.html">clause 27</a> and / or the National Employment Standards.</p><p><strong>a.</strong> Return to work Guarantee</p><p><strong>(i)</strong> An Employee must confirm to the Employer their return to work after a period of Parental Leave at least four weeks prior to the end of the leave, or where that is not practicable, as soon as practicable.</p><p><strong>(ii)</strong> Subject to clause 70.12a(iii), an Employee will be entitled to the position which they held immediately before proceeding on Parental Leave [which shall include Parental Leave extended in accordance with clause 70.11 in the case of an Employee transferred to a safe job pursuant to 70.14 or who reduced their working hours because of their pregnancy, the Employee will be entitled to return to the position they held immediately before such transfer or reduction.</p><p><strong>(iii)</strong> Where such position no longer exists but there are other positions available which the Employee is qualified for and is capable of performing, the Employee will be entitled to a position as nearly comparable in status and pay to that of their former position.</p><p><strong>b.</strong> Request to return to work part time The Employer will accommodate the reasonable needs of an Employee to return to work from Parental Leave on a part-time basis at the Employee’s substantive classification. Further:</p><p><strong>(i)</strong> Request</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>A request to return to work part-time must be made as soon as possible but no less than seven weeks prior to the date upon which the Employee is due to return to work from Parental Leave.</p><p><strong>(ii)</strong> Request and Response to be in writing The Employee’s request and the Employer’s decision made under this clause must be recorded in writing. The Employer must give the Employee a written response as soon as practicable, and no later than 21 days after the request is made. Where an Employer refuses a request on reasonable business grounds, the Employer’s response must include details of the reasons for the refusal.</p><p><strong>(iii)</strong> Dispute resolution Where the Employer experiences a genuine inability to accommodate such a request on operational grounds, the matter will be referred to the Dispute Settling Procedure at <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11</a> for resolution.</p><p><strong>(iv)</strong> Agreement to be in writing An agreement reached between an Employee and Employer in relation to a request to return to work part-time must be recorded as a temporary variation to the Employee’s employment contract. A copy of the variation will be given to the Employee.</p><p><strong>(v)</strong> No new or replacement contract An Employer will not offer, propose or require an Employee who makes a request under this clause to sign a new or replacement employment contract, or through any other means change the Employee’s employment status.</p><p><strong>70.13</strong> Parental Leave And Other Entitlements</p><p><strong>a.</strong> An Employee may in lieu of or in conjunction with Parental Leave, access any Annual Leave or Long Service Leave entitlements which they have accrued subject to the total amount of leave not exceeding 52 weeks or a longer period as agreed under 70.11.</p><p><strong>b.</strong> Where an Employee not then on Parental leave is suffering from an illness whether related or not to pregnancy an Employee may take any paid Personal Leave to which she is entitled and/or unpaid Personal Leave in accordance with the relevant Personal Leave provisions.</p><p><strong>c.</strong> Employees who take leave under clause 70.13a may with the agreement of their employer:</p><p><strong>(i)</strong> take a period of annual leave, long service leave or ADOs as part of, or in addition to any period of parental leave.</p><p><strong>(ii)</strong> provided that where a birth occurs earlier than the proposed date of commencement of paid parental leave, that leave will be deemed to commence immediately after the expiration of the period of paid annual leave, long service leave or ADO(s).</p><p><strong>70.14</strong> Transfer To A Safe Job</p><p><strong>a.</strong> Where an Employee is pregnant and, in the opinion of a registered medical practitioner, the Employee is fit for work but due to illness or risks arising out of the pregnancy or hazards connected with the work assigned to the Employee make it inadvisable for the Employee to continue at their present work or at their current hours, the Employee will be transferred to a safe job, or by agreement with the Employee they will remain in their current job with reduced</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>hours of work, with no other change to the Employee’s terms and conditions of employment until the commencement of Parental Leave.</p><p><strong>b.</strong> Where no appropriate safe job exists or where a reduction in hours is not practicable or agreed, the Employee is entitled to take paid no safe job leave, at the Employee’s current rate of pay for their ordinary hours of work for the risk period.</p><p><strong>c.</strong> If the Employee is on paid no safe job leave during the six week period before the expected date of birth of the child and the Employee has failed to comply with a request by the Employer for a medical certificate stating whether the Employee is fit for work, the Employer may require the Employee to take unpaid parental leave or any paid leave to which they are entitled provided that an Employee is not entitled to take paid personal/carer’s leave or compassionate leave while they are taking unpaid parental leave.</p><p><strong>d.</strong> If the Employee’s pregnancy ends before the end of the risk period, the risk period ends when the pregnancy ends.</p><p><strong>e.</strong> The entitlement to paid no safe job leave is in addition to any other leave entitlement the Employee has.</p><p><strong>70.15</strong> Replacement Employees</p><p><strong>a.</strong> A replacement Employee is an Employee specifically engaged or temporarily promoted or transferred, as a result of an Employee proceeding on Parental Leave.</p><p><strong>b.</strong> Before an Employer engages a replacement Employee the Employer must inform that person of the temporary nature of the employment and of the rights of the Employee who is being replaced and of the rights of the Employer.</p><p><strong>70.16</strong> Communication During Parental Leave</p><p><strong>a.</strong> Where an Employee is on Parental Leave and a definite decision has been made to introduce significant change at the workplace (including Major Change under <a href="/eba/ebas/mspp/employment/30-consultation.html">clause 30.2c</a>), the Employer shall take reasonable steps to:</p><p><strong>(i)</strong> make information available in relation to any significant effect the change will have on the status or responsibility level of the position the Employee held before commencing Parental Leave; and</p><p><strong>(ii)</strong> provide an opportunity for the Employee to discuss any significant effect the change will have on the status or responsibility level of the position the Employee held before commencing Parental Leave.</p><p><strong>b.</strong> The Employee shall notify the Employer of changes of address or other contact details which might affect the Employer’s capacity to comply with 70.16a.</p><p><strong>70.17</strong> Keeping in Touch Days</p><p><strong>a.</strong> During a period of parental leave, the Employer and Employee may agree to perform work for the purpose of keeping in touch in order to facilitate a return to employment at the end of the period of leave.</p><p><strong>b.</strong> Keeping in touch days must be agreed and be in accordance with section 79A of the Act.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>Plain language terms: maternity, paternity, baby leave, adoption leave.</p>',155)])])}const g=t(n,[["render",i]]);export{c as __pageData,g as default};
